python3 << 'EOF'
import json
import re

# Read files
with open('manifest.json', 'r') as f:
    manifest = json.load(f)

with open('schema.json', 'r') as f:
    schema = json.load(f)

# Manual validation
errors = []

# Check release
if 'release' not in manifest:
    errors.append("✗ Missing 'release' field")
elif not re.match(r'^v[0-9]+\.[0-9]+\.[0-9]+$', manifest['release']):
    errors.append(f"✗ release '{manifest['release']}' does not match pattern ^v[0-9]+\\.[0-9]+\\.[0-9]+$")

# Check components
if 'components' not in manifest:
    errors.append("✗ Missing 'components' field")
else:
    components = manifest['components']

    if not isinstance(components, list):
        errors.append(f"✗ 'components' must be array, got {type(components).__name__}")
    elif len(components) != 3:
        errors.append(f"✗ 'components' must have exactly 3 items, got {len(components)}")
    else:
        # Check each component
        for i, comp in enumerate(components):
            if not isinstance(comp, dict):
                errors.append(f"✗ components[{i}] must be object, got {type(comp).__name__}")
                continue

            if 'name' not in comp:
                errors.append(f"✗ components[{i}] missing 'name'")
            elif not isinstance(comp['name'], str) or len(comp['name']) == 0:
                errors.append(f"✗ components[{i}].name must be non-empty string")

            if 'version' not in comp:
                errors.append(f"✗ components[{i}] missing 'version'")
            elif not re.match(r'^[0-9]+\.[0-9]+\.[0-9]+$', comp['version']):
                errors.append(f"✗ components[{i}].version '{comp['version']}' does not match pattern")

            if len(comp) > 2:
                extra = [k for k in comp.keys() if k not in ['name', 'version']]
                errors.append(f"✗ components[{i}] has extra properties: {extra}")

# Check no extra properties at root
extra_at_root = [k for k in manifest.keys() if k not in ['release', 'components']]
if extra_at_root:
    errors.append(f"✗ Root has extra properties: {extra_at_root}")

# Report
if errors:
    print("VALIDATION FAILED:")
    for error in errors:
        print(error)
else:
    print("✓ manifest.json is VALID against schema.json")
    print()
    print("  release:", manifest['release'])
    print("  components:")
    for i, comp in enumerate(manifest['components']):
        print(f"    [{i}] {comp['name']} {comp['version']}")
    print()
    print("✓ All 3 components present in correct order")
    print("✓ Each component has only 'name' and 'version' properties")
    print("✓ release field preserved as v2.4.0")

EOF
